  ('aboriginal-e3452428-moex-00342', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '依行政程序法規定，關於行政機關與人民締結之行政契約，下列敘述何者正確？', '["行政機關得就相對人契約之履行，依言詞或書面約定之方式，為必要之指導或協助", "行政機關為防止或除去對公益之重大危害，得於必要範圍內調整契約內容或終止契約", "因有情事重大變更，非當時所得預料，而依原約定顯失公平時，行政機關應以行政處分適當調 整契約內容", "行政契約約定自願接受執行，締約之一方為中央行政機關時，應經行政院之認可"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
