  ('aboriginal-e3452428-moex-00347', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '某電信業者，不服國家通訊傳播委員會對其所為之行政處分，應向何者提起訴願？', '["行政院", "國家通訊傳播委員會", "國家通訊傳播委員會所設置之訴願審議委員會", "交通部"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00348', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '受理訴願機關如認為訴願有理由時，其所為之處置，下列何者錯誤？', '["應以決定撤銷原行政處分之全部或一部", "得視事件之情節，逕為變更之決定", "得視事件之情節，發回原行政處分機關另為處分", "於訴願人表示不服之範圍內，得為更不利益之變更或處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00349', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '關於課予義務訴訟之敘述，下列何者錯誤？', '["除法律另有規定外，提起課予義務訴訟，應先提起訴願", "提起課予義務訴訟並無起訴期間之限制", "提起課予義務訴訟，得合併請求損害賠償", "課予義務訴訟係請求被告機關作出行政處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL),
  ('aboriginal-e3452428-moex-00350', 'aboriginal-e3452428', 'aboriginal-e3452428-moex-111-3082b5f1', 'sub-aboriginal-e3452428-03', NULL, 'single_choice', '國防部進行戰機起降演習，因巨大聲響造成鄰近鴨農養殖之鴨子大量死亡，鴨農得請求下列何項 救濟？', '["國防部飛行員因過失而未降低戰機起降時之噪音，飛行員應負國家賠償責任", "國防部因已設置噪音隔離設施，國防部不負任何填補責任", "鴨農所受之財產損失乃因公益而受特別犧牲，國防部應負損失補償責任", "此不屬於國家賠償法規範之範圍，人民應依民法請求國防部賠償其損害"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:58+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "502", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "一般民政"}'::jsonb, NULL)
